"""Arithmetic expression evaluator.

Supports +, -, *, / and right-associative ** with standard precedence,
parentheses, unary minus, and integer/decimal literals.  All arithmetic is
performed in floats.  Malformed input raises ValueError; division by zero
raises ZeroDivisionError.
"""

import re

_NUMBER = re.compile(r"\d+(?:\.\d*)?|\.\d+", re.ASCII)


def _tokenize(expr):
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
            continue
        m = _NUMBER.match(expr, i)
        if m:
            tokens.append(float(m.group()))
            i = m.end()
        elif expr.startswith("**", i):
            tokens.append("**")
            i += 2
        elif c in "+-*/()":
            tokens.append(c)
            i += 1
        else:
            raise ValueError("illegal character %r at position %d" % (c, i))
    return tokens


class _Parser:
    """Recursive-descent parser over a token list.

    Grammar:
        expr  := term  (('+' | '-') term)*
        term  := unary (('*' | '/') unary)*
        unary := '-' unary | power
        power := atom ('**' unary)?      # exponent recurses through unary,
        atom  := NUMBER | '(' expr ')'   # so ** is right-associative and
                                         # binds tighter than unary minus
    """

    def __init__(self, tokens):
        self._tokens = tokens
        self._pos = 0

    def _peek(self):
        if self._pos < len(self._tokens):
            return self._tokens[self._pos]
        return None

    def _advance(self):
        tok = self._peek()
        self._pos += 1
        return tok

    def parse(self):
        value = self._expr()
        if self._pos != len(self._tokens):
            raise ValueError("unexpected token %r" % (self._tokens[self._pos],))
        return value

    def _expr(self):
        value = self._term()
        while self._peek() in ("+", "-"):
            if self._advance() == "+":
                value += self._term()
            else:
                value -= self._term()
        return value

    def _term(self):
        value = self._unary()
        while self._peek() in ("*", "/"):
            if self._advance() == "*":
                value *= self._unary()
            else:
                value /= self._unary()
        return value

    def _unary(self):
        if self._peek() == "-":
            self._advance()
            return -self._unary()
        return self._power()

    def _power(self):
        base = self._atom()
        if self._peek() == "**":
            self._advance()
            return base ** self._unary()
        return base

    def _atom(self):
        tok = self._peek()
        if isinstance(tok, float):
            self._advance()
            return tok
        if tok == "(":
            self._advance()
            value = self._expr()
            if self._peek() != ")":
                raise ValueError("unbalanced parentheses")
            self._advance()
            return value
        if tok is None:
            raise ValueError("unexpected end of expression")
        raise ValueError("unexpected token %r" % (tok,))


def evaluate(expr: str) -> float:
    tokens = _tokenize(expr)
    if not tokens:
        raise ValueError("empty expression")
    return _Parser(tokens).parse()
